import React, { useState } from "react";

export default function Chatbot({ disease, precautions = [] }) {
  const [messages, setMessages] = useState([
    { from: "bot", text: "👋 AI Doctor here" }
  ]);
  const [input, setInput] = useState("");

  const reply = (msg) => {
    msg = msg.toLowerCase();

    if (msg.includes("treatment")) return `Treatment for ${disease}: rest & meds`;
    if (msg.includes("diet")) return `Healthy diet for ${disease}`;
    if (msg.includes("precaution")) return precautions.join(", ");

    return "Ask about treatment, diet, precautions";
  };

  const send = () => {
    setMessages([...messages,
      { from: "user", text: input },
      { from: "bot", text: reply(input) }
    ]);
    setInput("");
  };

  return (
    <div className="glass">
      <h3>🤖 AI Doctor</h3>

      {messages.map((m, i) => (
        <p key={i}>{m.text}</p>
      ))}

      <input value={input} onChange={e => setInput(e.target.value)} />
      <button onClick={send}>Send</button>
    </div>
  );
}
